import{_ as o,o as e,c as t,Q as a}from"./chunks/framework.2275ac6f.js";const u=JSON.parse('{"title":"Ubuntu20.04 安装 MongoDB 和 MongoShell","description":"","frontmatter":{"date":"2023-04-03T00:28:00.000Z"},"headers":[{"level":2,"title":"卸载","slug":"卸载","link":"#卸载","children":[]},{"level":2,"title":"安装","slug":"安装","link":"#安装","children":[]}],"relativePath":"src/linux/ub20.04安装mongodb.md","lastUpdated":1718000534000}'),n={name:"src/linux/ub20.04安装mongodb.md"},r=a('<h1 id="ubuntu20-04-安装-mongodb-和-mongoshell" tabindex="-1">Ubuntu20.04 安装 MongoDB 和 MongoShell <a class="header-anchor" href="#ubuntu20-04-安装-mongodb-和-mongoshell" aria-hidden="true">#</a></h1><p>之前用 apt 安装的 Mongo3.x, 先卸载!</p><h2 id="卸载" tabindex="-1">卸载<sup class="footnote-ref"><a href="#fn1" id="fnref1">[1]</a></sup> <a class="header-anchor" href="#卸载" aria-hidden="true">#</a></h2><ol><li><p>停止 mongodb 服务 sudo service mongod stop</p></li><li><p>卸载 mongodb sudo apt-get remove mongodb</p></li><li><p>移除相关包 sudo apt-get purge mongodb-org sudo apt-get purge mongodb sudo apt-get autoremove sudo apt-get autorclean</p></li><li><p>移除相关目录 sudo rm -r /var/log/mongodb sudo rm -r /var/lib/mongodb</p></li><li><p>查看系统还有哪些残留的文件或目录 whereis mongo whereis mongodb whereis mongod which mongo which mongodb which mongod</p></li></ol><h2 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-hidden="true">#</a></h2><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>我是 Ubuntu20.04, 其他版本可能不能这样安装! 可以通过<code>lsb_release -dc</code>指令查看自己的发行版</p></div><p>分别下载这些 deb 包然后用<code>sudo dpkg -i xxxx.deb</code>来安装</p><ul><li><a href="https://www.mongodb.com/try/download/community" target="_blank" rel="noreferrer">MongoDB Community Server</a> MongoDB 的服务端</li><li><a href="https://www.mongodb.com/try/download/compass" target="_blank" rel="noreferrer">MongoDB Shell Download</a> MongoShell 在 6.x 版本需要单独下载安装(和以前的<code>mongo</code>指令类似), 通过<code>mongosh</code>进入 mongo shell</li><li><a href="https://www.mongodb.com/try/download/database-tools" target="_blank" rel="noreferrer">MongoDB Command Line Database Tools Download</a> 这里有<code>mongodump</code>和<code>mongorestore</code><sup class="footnote-ref"><a href="#fn2" id="fnref2">[2]</a></sup></li></ul><hr class="footnotes-sep"><section class="footnotes"><ol class="footnotes-list"><li id="fn1" class="footnote-item"><p><a href="https://zhuanlan.zhihu.com/p/347614929" target="_blank" rel="noreferrer">https://zhuanlan.zhihu.com/p/347614929</a> <a href="#fnref1" class="footnote-backref">↩︎</a></p></li><li id="fn2" class="footnote-item"><p><a href="https://www.mongodb.com/docs/database-tools/" target="_blank" rel="noreferrer">https://www.mongodb.com/docs/database-tools/</a> <a href="#fnref2" class="footnote-backref">↩︎</a></p></li></ol></section>',10),l=[r];function s(d,i,c,h,m,g){return e(),t("div",null,l)}const f=o(n,[["render",s]]);export{u as __pageData,f as default};
